  "PHIL 80E": {
    title: "Latin American Philosophy",
    units: 5, division: "lower",
    prereqs: [],
    ge: null, quarters: ["F", "W", "S", "SU"],
    desc: "Is there a general school of philosophy endemic to Latin America? Would it have to appeal to quintessential Western philosophical questions regarding knowledge, values, and reality? If not, why not, and would it then still count as philosophy? What difference do ethnic and national diversity, as well as strong political and social inequality, make to the development of philosophical questions and frameworks? Course explores a variety of historically situated Latin American thinkers who investigate ethnic identity, gender, and socio-political inequality and liberation, and historical memory, and who have also made important contributions to mainstream analytical and continental philosophy.",
    section: ["FREE"], rmpScore: 0
  },
  "THEA 161P": {
    title: "Theater in the Chicano Power Movement",
    units: 5, division: "upper",
    prereqs: [],
    ge: "ER", quarters: ["F", "W", "S", "SU"],
    desc: "Covers the rise of Teatro Chicano as a cultural-political force within the 1960's Chicano Power Movement starting with founding playwriter Luis Valdez and El Teatro Campesino and covering Chicana/o playwrights inspired by the movement, e.g. Cherrie Moraga, Luis Alfaro, and Josefina Lopez.",
    section: ["FREE"], rmpScore: 0
  },
  "THEA 161R": {
    title: "Theatre of American Cultures: Fighting Oppression",
    units: 5, division: "upper",
    prereqs: [],
    ge: null, quarters: ["F", "W", "S", "SU"],
    desc: "Course uses theory and practice to explore Theater of the Oppressed (T.O.), a humanist theatrical form with its roots in social justice that breaks the boundary between audience and stage. Through audience participation as \"spect-actors\" everyone is invited to move from passive to active to imagine and embody social change. Led by jokers, who \"difficultate\" rather than \"facilitate,\" T.O. has been used by groups around the world to explore, understand, and fight back against a wide range of oppressions. Students practice the games, techniques, methodology, and practical application of this activist theater form, explore the oxymoron of a T.O. class at UCSC, and discover what is possible when we become active creators of knowledge through theater. (Formerly Theater of American Cultures.)",
    section: ["FREE"], rmpScore: 0
  },
