  "ESCI 150": {
    title: "Field and Laboratory Methods in Coastal and Aquatic Science",
    units: 5, division: "upper",
    prereqs: [["CHEM 3C", "CHEM 4B", "CHEM 1C", "PHYS 5B", "PHYS 6B", "MATH 11B", "MATH 19B", "ESCI 30", "BIOE 20C"]],
    ge: "PR-E", quarters: ["F", "W", "S", "SU"],
    desc: "Students become familiar with some of the core measurement and sampling techniques routinely employed by working aquatic scientists. In keeping with the multi-disciplinary nature of aquatic science, these techniques and measurements include those taken from biology, geology, chemistry and physics. The overarching goal of is having students become deeply familiar with a field site and observing it over an extended period of time while working collaboratively to accomplish all the measurements. The field component of the work is conducted at UCSC's Younger Lagoon Research Reserve, located adjacent to the Long Marine Lab on the coastal campus. Taught in conjunction with OCEA 250 ; students cannot receive credit for this course and OCEA 250 .",
    section: ["FREE"], rmpScore: 0
  },
  "ESCI 160": {
    title: "Data Analysis in the Environmental Sciences",
    units: 5, division: "upper",
    prereqs: [["MATH 11B", "MATH 19B"]],
    ge: "SR", quarters: ["F", "W", "S", "SU"],
    desc: "Introduces data-analysis methods regularly encountered within environmental sciences. Students learn how to think about data, its uncertainty, how models and data are related and depend on underlying assumptions, and how to synthesize information contained in data.",
    section: ["FREE"], rmpScore: 0
  },
  "ESCI 167": {
    title: "Applied Environmental Time Series Analysis",
    units: 5, division: "upper",
    prereqs: [["ESCI 160", "EART 125", "OCEA 260", "EART 260"]],
    ge: null, quarters: ["F", "W", "S", "SU"],
    desc: "Explores empirical approach to quantify and explain changes in the Earth system over time. With the complexity of the Earth system, and the challenge of making accurate and numerous observations, simple methods can be of limited usefulness. Course covers more advanced methods that are typically not included in introductory-level statistical courses. Students learn how to analyze time-series data and answer questions about the Earth system and acquire the theoretical basis of the statistical approaches, the experience at conducting analyses, and practice interpreting and discussing the results. This class is hands-on and utilizes a suite of observational datasets and outputs from Earth system models. Students cannot receive credit for this course and OCEA 267 .",
    section: ["FREE"], rmpScore: 0
  },
